+/// fs.fdatasyncSync(fd) - Flush file data to disk (not metadata)
+fn fsFdatasyncSync(ctx: ?*qjs.JSContext, _: qjs.JSValue, argc: c_int, argv: [*c]qjs.JSValue) callconv(.c) qjs.JSValue {
+    if (argc < 1) {
